    public static void main(String[] args) {
        WLyricObj obj = new Gson().fromJson(temp, WLyricObj.class);
        LyricDecoder docoder = new LyricDecoder();
        docoder.check(obj);

        System.setOut(new PrintStream(System.out, true, StandardCharsets.UTF_8));

        LyricSave save = new LyricSave();
        save.setLyric(docoder.getLyrics());
        save.setKlyric(docoder.getKLyric());

        int a = 0;
        do {
            a += 10;

            if (save.lyricGetNext(a)) {
                System.out.println("time: " + a + " lyric: " + save.getNow().lyric);
            }
            if (save.updateKtv(a)) {
                System.out.println("time: " + a + " klyric: " + save.getKtvNow().build());
            }

        } while (a <= 1000000);
    }
